#include <stdio.h>
struct Stat { int min; int max; float avg; };
struct Stat compute(int a, int b, int c) {
    struct Stat s;
    s.min = a < b ? (a < c ? a : c) : (b < c ? b : c);
    s.max = a > b ? (a > c ? a : c) : (b > c ? b : c);
    s.avg = (a + b + c) / 3.0;
    return s;
}
int main() {
    struct Stat r = compute(5, 10, 15);
    printf("%d", r.max);
    return 0;
}

