#include <stdio.h>
struct Interval { double low; double high; };
struct Interval intersect(struct Interval a, struct Interval b) {
    double lo = a.low > b.low ? a.low : b.low;
    double hi = a.high < b.high ? a.high : b.high;
    return (struct Interval){lo, hi};
}
int main() {
    struct Interval r = intersect((struct Interval){1.0, 5.0}, (struct Interval){3.0, 7.0});
    printf("%.0f", r.low);
    return 0;
}

