#include <stdio.h>
struct BST {
    int key;
    struct BST *left;
    struct BST *right;
};
struct BST* search(struct BST *root, int key) {
    if(!root || root->key == key) return root;
    if(key < root->key) return search(root->left, key);
    return search(root->right, key);
}
int main() {
    struct BST n3 = {75, NULL, NULL};
    struct BST n2 = {25, NULL, NULL};
    struct BST n1 = {50, &n2, &n3};
    struct BST *found = search(&n1, 25);
    printf("%d", found ? found->key : -1);
    return 0;
}

