#include <stdio.h>
struct Poly { int coeffs[10]; int degree; };
int eval(struct Poly p, int x) {
    int result = 0;
    int power = 1;
    for(int i = 0; i <= p.degree; i++) {
        result += p.coeffs[i] * power;
        power *= x;
    }
    return result;
}
int main() {
    struct Poly p = {{1, 2, 1}, 2};
    printf("%d", eval(p, 2));
    return 0;
}

