#include <stdio.h>
struct Version { int major; int minor; int patch; };
int compareVer(struct Version a, struct Version b) {
    if(a.major != b.major) return a.major - b.major;
    if(a.minor != b.minor) return a.minor - b.minor;
    return a.patch - b.patch;
}
int main() {
    struct Version v1 = {1, 2, 3};
    struct Version v2 = {1, 2, 4};
    printf("%d", compareVer(v1, v2) < 0 ? 1 : 0);
    return 0;
}

