#include <stdio.h>
struct MinMax { int min; int max; };
struct MinMax findMinMax(int *arr, int n) {
    struct MinMax mm = {arr[0], arr[0]};
    for(int i = 1; i < n; i++) {
        if(arr[i] < mm.min) mm.min = arr[i];
        if(arr[i] > mm.max) mm.max = arr[i];
    }
    return mm;
}
int main() {
    int arr[] = {5, 2, 8, 1, 9};
    struct MinMax r = findMinMax(arr, 5);
    printf("%d,%d", r.min, r.max);
    return 0;
}

#include <stdio.h>
struct Pair { const char *key; int value; };
int lookup(struct Pair *table, int n, const char *key) {
    for(int i = 0; i < n; i++) {
        int match = 1;
        for(int j = 0; table[i].key[j] && key[j]; j++) {
            if(table[i].key[j] != key[j]) { match = 0; break; }
        }
        if(match) return table[i].value;
    }
    return -1;
}
int main() {
    struct Pair t[] = {{"a", 1}, {"b", 2}, {"c", 3}};
    printf("%d", lookup(t, 3, "b"));
    return 0;
}

