#include <stdio.h>
struct LRU { int keys[4]; int vals[4]; int count; };
void lru_put(struct LRU *l, int k, int v) {
    for(int i = l->count; i > 0; i--) {
        l->keys[i] = l->keys[i-1];
        l->vals[i] = l->vals[i-1];
    }
    l->keys[0] = k;
    l->vals[0] = v;
    if(l->count < 4) l->count++;
}
int main() {
    struct LRU l = {{0}, {0}, 0};
    lru_put(&l, 1, 10);
    lru_put(&l, 2, 20);
    printf("%d", l.keys[0]);
    return 0;
}

