#include <stdio.h>
struct Multiset { int elem[100]; int cnt[100]; int uniq; };
void add(struct Multiset *m, int val) {
    for(int i = 0; i < m->uniq; i++) {
        if(m->elem[i] == val) { m->cnt[i]++; return; }
    }
    m->elem[m->uniq] = val;
    m->cnt[m->uniq++] = 1;
}
