#include <stdio.h>
struct UFNode { int parent; int rank; };
void unite(struct UFNode *uf, int x, int y) {
    int px = uf[x].parent, py = uf[y].parent;
    if(uf[px].rank < uf[py].rank) uf[px].parent = py;
    else if(uf[px].rank > uf[py].rank) uf[py].parent = px;
    else { uf[py].parent = px; uf[px].rank++; }
}
int main() {
    struct UFNode uf[3] = {{0,0}, {1,0}, {2,0}};
    unite(uf, 0, 1);
    printf("%d", uf[1].parent);
