struct Scheduler { int tasks[10]; int count; int current; };
int next(struct Scheduler *s) {
    if(s->count == 0) return -1;
    int task = s->tasks[s->current];
    s->current = (s->current + 1) % s->count;
    return task;
}
int main() {
