#include <stdio.h>
struct Timer { int interval; int elapsed; int active; };
void tick(struct Timer *t) {
    if(t->active) t->elapsed++;
}
int expired(struct Timer *t) {
    return t->elapsed >= t->interval;
}
int main() {
    struct Timer t = {3, 0, 1};
    tick(&t); tick(&t); tick(&t);
    printf("%d", expired(&t));
    return 0;
}

#include <stdio.h>
struct Watchdog { int timeout; int counter; };
void feed(struct Watchdog *w) { w->counter = 0; }
int check(struct Watchdog *w) {
    w->counter++;
    return w->counter >= w->timeout;
}
int main() {
    struct Watchdog w = {3, 0};
    check(&w); check(&w); feed(&w); check(&w);
    printf("%d", w.counter);
    return 0;
}

